patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..51c79c1e2273 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2256,6 +2256,37 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     if ((HighMask & *AndC).isZero())
       return BinaryOperator::CreateAnd(Op0, ConstantInt::get(Ty, ~(*AndC)));
   }
+  // C2 - ((C1 - X) & -K) --> X & result_mask
+  // where the inner sub has nuw, C2 = C1 & -K, and C1's low k bits are all 1s.
+  // This fold is valid because (C1 - X) & -K = C2 - (X & -K) when X <= C1
+  // and C1's low k bits are all 1s (no borrow into high bits).
+  // Then: C2 - ((C1 - X) & -K) = C2 - (C2 - (X & -K)) = X & -K
+  // Since X <= C1, high bits of X beyond C1's MSB are 0.
+  // So result_mask = -K & ((1 << (msb(C1)+1)) - 1)
+  Constant *SubC1, *SubC2, *AndMask;
+  Value *SubOp, *AndOp;
+  if (match(Op0, m_Constant(SubC2)) &&
+      match(Op1, m_And(m_Value(AndOp), m_Constant(AndMask))) &&
+      match(AndOp, m_Sub(m_Constant(SubC1), m_Value(SubOp)))) {
+    if (auto *AndI = dyn_cast<Instruction>(Op1)) {
+      if (auto *SubI = dyn_cast<Instruction>(AndOp)) {
+        if (SubI->hasNoUnsignedWrap()) {
+          const APInt *C1AP, *C2AP, *MaskAP;
+          if (match(SubC1, m_APInt(C1AP)) && match(SubC2, m_APInt(C2AP)) &&
+              match(AndMask, m_APInt(MaskAP))) {
+            APInt LowMask = ~*MaskAP;
+            if (!LowMask.isZero() && LowMask.isMask()) {
+              if ((*C1AP & LowMask) == LowMask && (*C1AP & *MaskAP) == *C2AP) {
+                unsigned BitWidth = Ty->getScalarSizeInBits();
+                unsigned MSBPos = C1AP->nearestLogBase2();
+                APInt BoundMask = APInt::getLowBitsSet(BitWidth, MSBPos + 1);
+                APInt ResultMask = *MaskAP & BoundMask;
+                return BinaryOperator::CreateAnd(SubOp, ConstantInt::get(Ty, ResultMask));
+          }
+        }
+      }
+    }
+  }

   if (Instruction *V =
           canonicalizeCondSignextOfHighBitExtractToSignextHighBitExtract(I))

